// Validate JWT from Authorization header
const crypto = require('crypto');
const authHeader = $json.headers?.authorization || $json.headers?.Authorization || '';
if (!authHeader.startsWith('Bearer ')) {
  return [{ json: { _error: 'missing_jwt', _status: 401 } }];
}
const token = authHeader.slice(7);
const parts = token.split('.');
if (parts.length !== 3) {
  return [{ json: { _error: 'invalid_jwt', _status: 401 } }];
}
const secret = $env.JWT_SECRET;
if (!secret) {
  return [{ json: { _error: 'server_misconfig_no_secret', _status: 500 } }];
}
const signingInput = parts[0] + '.' + parts[1];
const expected = crypto.createHmac('sha256', secret).update(signingInput).digest('base64')
  .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
if (expected !== parts[2]) {
  return [{ json: { _error: 'bad_signature', _status: 401 } }];
}
let payload;
try {
  const padded = parts[1] + '='.repeat((4 - parts[1].length % 4) % 4);
  payload = JSON.parse(Buffer.from(padded.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString());
} catch (e) {
  return [{ json: { _error: 'invalid_payload', _status: 401 } }];
}
const now = Math.floor(Date.now() / 1000);
if (payload.exp && payload.exp < now) {
  return [{ json: { _error: 'jwt_expired', _status: 401 } }];
}
return [{ json: { ...$json, _jwt_email: payload.sub, _jwt_jti: payload.jti } }];

