// Strip {{ESCALATE}} marker, generate localized fallback, preserve upstream data
const raw = $json.output || '';
const needsHuman = raw.includes('{{ESCALATE}}');

const webhook = $('Webhook').first()?.json || {};
const jwtData = $('JWT Validate').first()?.json || {};
const email = jwtData._jwt_email || '';
const lang = (webhook.body || {}).lang || 'en';

const FALLBACK = {
  de: `Diese Frage kann ich nicht sicher beantworten — Nina meldet sich persönlich bei dir auf ${email}.`,
  en: `I'm not sure about that one — Nina will get back to you personally at ${email}.`,
  fr: `Je ne peux pas répondre à cette question avec certitude — Nina te recontactera personnellement à ${email}.`,
  es: `No puedo responder esta pregunta con certeza — Nina te contactará personalmente en ${email}.`,
  it: `Non so rispondere a questa domanda con certezza — Nina ti ricontatterà personalmente a ${email}.`,
};

let clean = raw.replace(/\{\{ESCALATE\}\}/g, '').trim();
if (needsHuman && !clean) {
  clean = FALLBACK[lang] || FALLBACK.en;
}

return [{
  json: {
    output: raw,
    output_clean: clean,
    needs_human: needsHuman,
    body: webhook.body || {},
    _jwt_email: email,
    _jwt_jti: jwtData._jwt_jti || '',
  }
}];
